var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"케이스 37. 선별원 코드 B2-1.","JPN":"ケース37。選別人コードB2-1。","ENG":"Case 37. Subject code B2-1.","TWN":"案例編號，37。受試者代碼，B2-1。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"대상의 침식내성은 일반인을 조금 웃도는 수준이며, 비카운터로 분류된다.","JPN":"対象の侵食耐性は一般人を少し上回るレベルであり、非カウンターとして分類される。","ENG":"The subject's Corruption resistance is slightly above average and is classified as a non-Counter.","TWN":"實驗對象的侵蝕耐性略高於普通人，但仍舊被歸類為非制裁者。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"하지만 추출물 미드나잇 D타입에 부작용을 보이지 않은 유일한 케이스로, 일전에 시험한 6개 시약에 높은 반응성을 보였다.","JPN":"だが、抽出物ミッドナイトDタイプに副作用を見せなかった唯一のケースで、この前に試験した6つの試薬に高い反応性を見せた。","ENG":"However, she was the only subject who did not show any side effects to the extract Midnight Type D, while showing high responses to the 6 reagents tested previously.","TWN":"然而，作為唯一對午夜D型提取物沒有表現出副作用的案例，她對之前測試的6種試劑表現出極高的反應性。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"이번 테스트에선 시약을 대신해 혈액 샘플을 직접적으로 투여할 예정이다.","JPN":"今回のテストでは試薬の代わりに血液のサンプルを直接的に投与する予定だ。","ENG":"In this test, I will be administering the blood sample directly to her instead of a reagent.","TWN":"這次測試中我將直接為其注入血液樣本代替試劑。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"살아남는다면… 프로젝트의 큰 전환점이 되겠지.","JPN":"生き残れば……プロジェクトの大きなターニングポイントとなるだろう。","ENG":"If she lives... it will be a great turning point for the project.","TWN":"如果她能活下來……或許將成為計畫的重大轉捩點。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"…이리 와서 앉아라. B2-1.","JPN":"……ここに座れ。B2-1。","ENG":"...Come and sit down, B2-1.","TWN":"……過來坐下吧。B2-1。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"이제 뒤로 물러서.","JPN":"もう少し後ろに下がれ。","ENG":"Now, step back.","TWN":"現在退後。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"SAW_REAPER_PAST_CHILD","face":"UNIT_IDLE"},"R":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"지금 기분이 어떻지?","JPN":"今の気分はどうだ？","ENG":"How do you feel?","TWN":"感覺怎麼樣？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"SAW_REAPER_PAST_CHILD","face":"UNIT_IDLE"},"R":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SAW_REAPER_PAST_CHILD","text":{"KOREA":"뜨겁지만… 견딜만해요.","JPN":"熱いですけど……耐えられそうです。","ENG":"A little hot, but... nothing I can't handle.","TWN":"雖然很熱……但還能忍受。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"SAW_REAPER_PAST_CHILD","face":"UNIT_IDLE"},"R":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SAW_REAPER_PAST_CHILD","text":{"KOREA":"앞으로도… 제가 주사 다 맞을 수 있어요.","JPN":"これからも……私に全部の注射を打ってください。","ENG":"I'll be able to... take all future injections.","TWN":"我還可以……打很多針的。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"SAW_REAPER_PAST_CHILD","face":"UNIT_IDLE"},"R":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SAW_REAPER_PAST_CHILD","text":{"KOREA":"그러니… 그러니까…","JPN":"だから……だから……","ENG":"So... so...","TWN":"所以…… 所以說……"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"SAW_REAPER_PAST_CHILD","face":"UNIT_IDLE"},"R":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SAW_REAPER_PAST_CHILD","text":{"KOREA":"우리 오빠는 건들지 말아주-","JPN":"お兄ちゃんには手を出さないでくー","ENG":"Please don't touch my broth–","TWN":"不要碰我哥哥——"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"SAW_REAPER_PAST_CHILD","face":"UNIT_IDLE"},"R":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SAW_REAPER_PAST_CHILD","text":{"KOREA":"컥…! 커헉…","JPN":"がっ……！　かっは……","ENG":"Kuh...! Urgh...","TWN":"咳……！咳咳……"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"…회복하고 있군. 아주 인상적이야.","JPN":"……回復しているな。とてもすばらしい。","ENG":"…She's recovering. Impressive.","TWN":"……已經開始恢復了。真是印象深刻。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"B2-1. 일어서서 움직여봐라.","JPN":"B2-1。立ち上がって動いてみろ。","ENG":"B2-1. Get up and move around.","TWN":"B2-1。 站起來動一動。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SAW_REAPER_PAST_CHILD","text":{"KOREA":"아파요…","JPN":"痛いです……","ENG":"It hurts...","TWN":"可是……好痛……"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"일어서라. 어서.","JPN":"立て。早く。","ENG":"On your feet. Now.","TWN":"站起來，馬上。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SAW_REAPER_PAST_CHILD","text":{"KOREA":"하아… 하…","JPN":"はあ……はぁ……","ENG":"*Huff* *Huff*","TWN":"哈啊……哈……"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"폐를 관통했는데 벌써 숨을 쉴 정도로 회복하다니. 기대 이상의 결과야.","JPN":"肺を貫通したのに、もう息ができるほど回復するとは。期待以上の結果だ。","ENG":"It went right through her lungs, but she's already recovered enough to breathe. This is far beyond our expectations.","TWN":"肺都被穿透了，居然已經恢復到能呼吸的程度。我們獲得了超出預期的結果。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"다음은 뇌를 비롯한 급소부위의 재생 여부와 혈액 샘플의 효력 지속 시간을…","JPN":"次は脳を含む急所部位の再生可否と、血液サンプルの効力持続時間を……","ENG":"We should now test the regeneration of vital organs, including the brain, as well as the effect duration of the blood sample–","TWN":"接下來是關於大腦等重要部位的再生情況和血液樣本的效力持續時間……"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"음…?","JPN":"む……？","ENG":"Mm...?","TWN":"嗯……？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SAW_REAPER_PAST_CHILD","text":{"KOREA":"목이… 목이 타들어가…","JPN":"喉が……喉が渇いた……","ENG":"I need... something to drink...","TWN":"喉嚨……喉嚨有東西在燒……"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_NULL","text":{"KOREA":"B2-1! 물러서! 지금 뭐하는 거냐!","JPN":"B2-1！　下がれ！　今何をしている！","ENG":"B2-1! Stand back! What do you think you're doing?!","TWN":"B2-1！退後！你現在在幹什麼！"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"RESEARCHER_FLOOR_UNION_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};